(function (globalScope) {
    var BASE_PAYLOAD = {
        isv_id: "342353",
        v_name: "吉煜",
        v_phone: "15910303914",
        v_certificateNumber: "142723198811264416",
        v_dw: "ibm",
        v_personSum: "1",
        v_reason: "开会",
        secondVisitorType: "1281861295905177600",
        v_timeStr: "2025-12-04 08:10:00",
        v_lvTimeStr: "2025-12-04 23:42:00",
        v_plateNumber: "晋M39068",
        visitorType: 2,
        areaIds: "",
        areaIdList: [],
        faceFile: "data:image/jpeg;base64,",
        followVisitors: [],
        isv_type: null
    };

    var ENDPOINT_BASE = "https://fangk.yili.com:10443/evo-apigw/evo-visitor/1.0.0/card/visitor/appointment";

    function pad2(num) {
        return String(num).padStart(2, "0");
    }

    function formatDateTime(date, hour, minute, second) {
        return [
            date.getFullYear(),
            "-",
            pad2(date.getMonth() + 1),
            "-",
            pad2(date.getDate()),
            " ",
            pad2(hour),
            ":",
            pad2(minute),
            ":",
            pad2(second)
        ].join("");
    }

    function getTodayStartTime(now) {
        var date = now || new Date();
        return formatDateTime(date, 8, 0, 0);
    }

    function getTodayEndTime(now) {
        var date = now || new Date();
        return formatDateTime(date, 23, 56, 0);
    }

    function buildPayload(now, timeOverrides) {
        var date = now || new Date();
        var overrides = timeOverrides || {};

        return {
            isv_id: BASE_PAYLOAD.isv_id,
            v_name: BASE_PAYLOAD.v_name,
            v_phone: BASE_PAYLOAD.v_phone,
            v_certificateNumber: BASE_PAYLOAD.v_certificateNumber,
            v_dw: BASE_PAYLOAD.v_dw,
            v_personSum: BASE_PAYLOAD.v_personSum,
            v_reason: BASE_PAYLOAD.v_reason,
            secondVisitorType: BASE_PAYLOAD.secondVisitorType,
            v_timeStr: overrides.v_timeStr || getTodayStartTime(date),
            v_lvTimeStr: overrides.v_lvTimeStr || getTodayEndTime(date),
            v_plateNumber: BASE_PAYLOAD.v_plateNumber,
            visitorType: BASE_PAYLOAD.visitorType,
            areaIds: BASE_PAYLOAD.areaIds,
            areaIdList: [],
            faceFile: BASE_PAYLOAD.faceFile,
            followVisitors: [],
            isv_type: BASE_PAYLOAD.isv_type
        };
    }

    function getEndpoint(now) {
        var current = now || new Date();
        return ENDPOINT_BASE + "?systime=" + current.getTime();
    }

    var api = {
        BASE_PAYLOAD: BASE_PAYLOAD,
        ENDPOINT_BASE: ENDPOINT_BASE,
        getTodayStartTime: getTodayStartTime,
        getTodayEndTime: getTodayEndTime,
        buildPayload: buildPayload,
        getEndpoint: getEndpoint
    };

    if (typeof module !== "undefined" && module.exports) {
        module.exports = api;
    }

    globalScope.AppointmentUtils = api;
})(typeof window !== "undefined" ? window : globalThis);

